/**
 * Non-Associative Verification Script
 * Proves that (e1 * e2) * e3 !== e1 * (e2 * e3)
 */

import { compileOctonionicAST, formatOctonionState, OctonionicAST } from './octonionic-compiler';

console.log("==================================================");
console.log("  OCTONIONIC COMPILER: NON-ASSOCIATIVE ROUTING");
console.log("==================================================");

// AST 1: (e1 * e2) * e3
const astA: OctonionicAST = [['e1', 'e2'], 'e3'];

// AST 2: e1 * (e2 * e3)
const astB: OctonionicAST = ['e1', ['e2', 'e3']];

console.log(`\nCompiling Path A: [['e1', 'e2'], 'e3']`);
const stateA = compileOctonionicAST(astA);
console.log(`  State A -> ${formatOctonionState(stateA)}`);

console.log(`\nCompiling Path B: ['e1', ['e2', 'e3']]`);
const stateB = compileOctonionicAST(astB);
console.log(`  State B -> ${formatOctonionState(stateB)}`);

console.log("\n==================================================");
if (formatOctonionState(stateA) !== formatOctonionState(stateB)) {
  console.log(" VERDICT: ASSOCIATIVITY BROKEN. PARENTHESES ROUTED EXECUTION.");
  console.log(" We have successfully compiled logic using The Octonions.");
} else {
  console.log(" VERDICT: FAILED. Associativity was maintained.");
}
console.log("==================================================\n");
